mapper.insert:
insert into merchant (
    campus_id, merchant_code, name, logo, cover_image, description, announcement,
    contact_name, contact_phone, address_detail, sort, status, business_status,
    business_begin_time, business_end_time, create_time, update_time, create_user, update_user
) values (
    #{campusId}, #{merchantCode}, #{name}, #{logo}, #{coverImage}, #{description}, #{announcement},
    #{contactName}, #{contactPhone}, #{addressDetail}, #{sort}, #{status}, #{businessStatus},
    #{businessBeginTime}, #{businessEndTime}, #{createTime}, #{updateTime}, #{createUser}, #{updateUser}
)

mapper.update:
update merchant
campus_id = #{campusId}, merchant_code = #{merchantCode}, name = #{name}, logo = #{logo}, cover_image = #{coverImage}, description = #{description}, announcement = #{announcement}, contact_name = #{contactName}, contact_phone = #{contactPhone}, address_detail = #{addressDetail}, sort = #{sort}, status = #{status}, business_status = #{businessStatus}, business_begin_time = #{businessBeginTime}, business_end_time = #{businessEndTime}, update_time = #{updateTime}, update_user = #{updateUser}
where id = #{id}

mapper.select:
select * from merchant


        and campus_id = #{campusId}


        and status = #{status}


        and business_status = #{businessStatus}


        and name like concat('%', #{name}, '%')


order by sort asc, create_time desc

select m.id, m.campus_id campusId, c.name campusName, c.status campusStatus, m.merchant_code merchantCode, m.name, m.logo, m.cover_image coverImage, m.description, m.announcement, m.contact_name contactName, m.contact_phone contactPhone, m.address_detail addressDetail, m.sort, m.status, m.business_status businessStatus, m.business_begin_time businessBeginTime, m.business_end_time businessEndTime, c.delivery_fee deliveryFee, c.estimated_delivery_minutes estimatedDeliveryMinutes, c.service_phone servicePhone from merchant m join campus c on m.campus_id = c.id where m.status = 1
and m.campus_id = #{campusId}
order by m.sort asc, m.id asc
